import React from 'react';
import { Link } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { addToCartRequest } from '../redux/slices/cartSlice';
import { API_URL } from '../utils/api';

const ProductCard = ({ product }) => {
  const dispatch = useDispatch();
  const { loading } = useSelector((state) => state.cart);

  const handleAddToCart = (e) => {
    e.preventDefault();
    dispatch(addToCartRequest({ productId: product._id, quantity: 1 }));
  };

  const imageUrl = product.images && product.images.length > 0
    ? `${API_URL}${product.images[0]}`
    : '/placeholder-product.png';

  return (
    <div className="card group bg-white rounded-lg shadow-sm hover:shadow-md transition-shadow">
      <Link to={`/product/${product._id}`}>
        <div className="aspect-[4/3] bg-gray-100 relative overflow-hidden rounded-t-lg">
          <img
            src={imageUrl}
            alt={product.name}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
            onError={(e) => {
              e.target.src = 'https://via.placeholder.com/200x150?text=No+Image';
            }}
          />
          {product.allowInstallment && (
            <span className="absolute top-1.5 left-1.5 bg-green-500 text-white text-[10px] px-1.5 py-0.5 rounded">
              Installment
            </span>
          )}
        </div>
      </Link>
      <div className="p-2">
        <Link to={`/product/${product._id}`}>
          <h3 className="font-medium text-gray-800 hover:text-primary-600 text-xs leading-tight line-clamp-2">
            {product.name}
          </h3>
        </Link>
        <p className="text-gray-400 text-[10px] mt-0.5 line-clamp-1">
          {product.description}
        </p>
        <div className="mt-1 flex items-center justify-between gap-1">
          <span className="text-xs font-bold text-primary-600">
            ₦{product.price?.toLocaleString()}
          </span>
          <button
            onClick={handleAddToCart}
            disabled={loading || product.stock === 0}
            className={`px-2 py-0.5 rounded text-[10px] font-medium ${
              product.stock === 0
                ? 'bg-gray-200 text-gray-500 cursor-not-allowed'
                : 'bg-primary-600 text-white hover:bg-primary-700'
            }`}
          >
            {product.stock === 0 ? 'Out' : 'Add'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;
